# Store webhook secrets in environment variables or Secret Manager
WEBHOOK_SECRET = os.environ.get('WEBHOOK_SECRET', '')
ALLOWED_IPS = os.environ.get('ALLOWED_IPS', '').split(',')
MAX_PAYLOAD_SIZE = 1024 * 1024  # 1MB

def verify_webhook_signature(payload, signature, secret):
    """Verify HMAC signature of webhook payload"""
    if not signature or not secret:
        return False
    
    expected_signature = hmac.new(
        secret.encode('utf-8'),
        payload,
        hashlib.sha256
    ).hexdigest()
    
    return hmac.compare_digest(signature, expected_signature)

def validate_ip_whitelist(request):
    """Validate request comes from allowed IP addresses"""
    if not ALLOWED_IPS or ALLOWED_IPS == ['']:
        return True
    
    client_ip = request.headers.get('X-Forwarded-For', '').split(',')[0].strip()
    if not client_ip:
        client_ip = request.remote_addr
    
    return client_ip in ALLOWED_IPS

def validate_request_size(request):
    """Validate request payload size"""
    content_length = request.content_length
    if content_length and content_length > MAX_PAYLOAD_SIZE:
        return False
    return True

def validate_content_type(request):
    """Validate content type is JSON"""
    content_type = request.headers.get('Content-Type', '')
    return 'application/json' in content_type

